def parse_api_error(resp: httpx.Response) -> AgentAPIError:
    try:
        body = resp.json()
    except ValueError:
        body = {"message": resp.text[:500]}

    if resp.status_code == 429:
        return RateLimitError(body.get("retry_after"))
    if resp.status_code in (502, 503, 504):
        return TransientAPIError(resp.status_code, body)
    if resp.status_code == 401:
        return AuthError(body.get("message", "unauthorized"))
    if 400 <= resp.status_code < 500:
        return ClientAPIError(resp.status_code, body)
    return ServerAPIError(resp.status_code, body)

def tool_error_for_model(exc: Exception) -> dict:
    if isinstance(exc, ClientAPIError):
        return {"ok": False, "error": f"Invalid request: {exc.message}"}
    if isinstance(exc, TransientAPIError):
        return {"ok": False, "error": "Service temporarily unavailable; retry later."}
    return {"ok": False, "error": "Tool failed unexpectedly."}

def call_tool_safe(fn, **kwargs) -> dict:
    try:
        return {"ok": True, "data": fn(**kwargs)}
    except RateLimitError as exc:
        time.sleep(exc.retry_after or 1)
        return call_tool_safe(fn, **kwargs)  # bounded retry wrapper
    except ClientAPIError as exc:
        return tool_error_for_model(exc)
    except Exception:
        log.exception("tool error")
        return {"ok": False, "error": "Internal tool error"}

